import 'dart:async';
import 'package:flutter/material.dart';
import 'package:vector_math/vector_math.dart' hide Colors;

/// Replayable decision for [AnimatedFractalController.animateParameter].
///
/// Parameter animation only supports numeric interpolation. Keeping that
/// contract explicit prevents unsupported boolean/string changes from arming a
/// transition that no animation can ever complete.
enum AnimatedParameterTransitionKind {
  unchanged,
  numeric,
  unsupported,
}

/// Pure parameter-transition plan derived from two parameter values.
final class AnimatedParameterTransitionPlan {
  final AnimatedParameterTransitionKind kind;
  final double? fromValue;
  final double? toValue;

  const AnimatedParameterTransitionPlan._({
    required this.kind,
    this.fromValue,
    this.toValue,
  });

  factory AnimatedParameterTransitionPlan.fromValues(Object from, Object to) {
    if (from == to) {
      return const AnimatedParameterTransitionPlan._(
        kind: AnimatedParameterTransitionKind.unchanged,
      );
    }

    if (from is num && to is num) {
      return AnimatedParameterTransitionPlan._(
        kind: AnimatedParameterTransitionKind.numeric,
        fromValue: from.toDouble(),
        toValue: to.toDouble(),
      );
    }

    return const AnimatedParameterTransitionPlan._(
      kind: AnimatedParameterTransitionKind.unsupported,
    );
  }

  bool get startsTransition => kind == AnimatedParameterTransitionKind.numeric;
}

/// Replayable frame plan for timer-driven animations.
///
/// Morph timers derive curve input from a duration and frame cadence. Keeping
/// that conversion explicit prevents sub-frame durations from producing zero
/// total steps and sending Infinity/NaN into Flutter curves.
final class AnimatedTimelinePlan {
  static const int defaultFramesPerSecond = 60;

  final Duration duration;
  final int framesPerSecond;
  final Duration frameInterval;
  final int totalFrames;

  const AnimatedTimelinePlan._({
    required this.duration,
    required this.framesPerSecond,
    required this.frameInterval,
    required this.totalFrames,
  })  : assert(framesPerSecond > 0, 'framesPerSecond must be positive'),
        assert(frameInterval > Duration.zero, 'frameInterval must be positive'),
        assert(totalFrames > 0, 'totalFrames must be positive');

  factory AnimatedTimelinePlan.forDuration(
    Duration duration, {
    int framesPerSecond = defaultFramesPerSecond,
  }) {
    final safeFramesPerSecond =
        framesPerSecond > 0 ? framesPerSecond : defaultFramesPerSecond;
    final frameIntervalMs = 1000 ~/ safeFramesPerSecond;
    final rawFrames = duration.inMicroseconds <= 0
        ? 1
        : (duration.inMicroseconds *
                safeFramesPerSecond /
                Duration.microsecondsPerSecond)
            .round();

    return AnimatedTimelinePlan._(
      duration: duration,
      framesPerSecond: safeFramesPerSecond,
      frameInterval: Duration(
        milliseconds: frameIntervalMs > 0 ? frameIntervalMs : 1,
      ),
      totalFrames: rawFrames > 0 ? rawFrames : 1,
    );
  }

  bool get isImmediate => duration <= Duration.zero;

  double progressForFrame(int frame) {
    if (frame <= 0) return 0.0;
    return (frame / totalFrames).clamp(0.0, 1.0).toDouble();
  }

  bool isCompleteFrame(int frame) => frame >= totalFrames;
}

/// Replayable progress contract for elapsed timer animations.
///
/// Parameter/view animations are driven by wall-clock elapsed time. A
/// non-positive duration is an immediate transition, matching morph timelines;
/// otherwise a negative duration can leave an animation permanently at 0%.
final class AnimatedElapsedProgress {
  final Duration duration;
  final Duration elapsed;

  const AnimatedElapsedProgress({
    required this.duration,
    required this.elapsed,
  });

  double get value {
    if (duration <= Duration.zero) return 1.0;
    if (elapsed <= Duration.zero) return 0.0;
    return (elapsed.inMicroseconds / duration.inMicroseconds)
        .clamp(0.0, 1.0)
        .toDouble();
  }

  bool get isComplete => value >= 1.0;
}

/// Service that manages smooth animated transitions for fractal parameters.
///
/// This service provides interpolated values for parameters during transitions,
/// enabling smooth morphing effects when changing fractal settings.
class AnimatedFractalController extends ChangeNotifier {
  /// Animation duration for parameter changes.
  final Duration parameterDuration;

  /// Animation duration for module (fractal type) changes.
  final Duration morphDuration;

  /// Animation curve for transitions.
  final Curve curve;

  // Internal state
  final Map<String, _AnimatedValue> _animatedParams = {};
  _AnimatedValue<double>? _animatedZoom;
  _AnimatedValue<Vector2>? _animatedPan;
  _AnimatedValue<Vector3>? _animatedRotation;

  String? _previousModuleId;
  String? _currentModuleId;
  double _morphProgress = 1.0;
  Timer? _morphTimer;
  Timer? _celebrationTimer;

  bool _isCelebrating = false;
  bool _isTransitioning = false;

  // Interesting spot detection
  int _interestingSpotCount = 0;
  DateTime? _lastInterestingSpotTime;
  final _interestingSpotController = StreamController<void>.broadcast();

  AnimatedFractalController({
    this.parameterDuration = const Duration(milliseconds: 250),
    this.morphDuration = const Duration(milliseconds: 600),
    this.curve = Curves.easeOutCubic,
  });

  /// Stream that emits when an interesting spot is found.
  Stream<void> get onInterestingSpot => _interestingSpotController.stream;

  /// Whether a celebration effect should be shown.
  bool get isCelebrating => _isCelebrating;

  /// Whether the controller is currently transitioning between states.
  bool get isTransitioning => _isTransitioning;

  /// Progress of the current morph transition (0.0 to 1.0).
  double get morphProgress => _morphProgress;

  /// The previous module ID during a morph transition.
  String? get previousModuleId => _previousModuleId;

  /// The current module ID.
  String? get currentModuleId => _currentModuleId;

  /// Start a parameter transition.
  void animateParameter(String id, Object from, Object to) {
    final plan = AnimatedParameterTransitionPlan.fromValues(from, to);
    if (!plan.startsTransition) return;

    _isTransitioning = true;
    notifyListeners();

    _animatedParams[id] = _AnimatedValue<double>(
      from: plan.fromValue!,
      to: plan.toValue!,
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedParams.remove(id);
        _checkTransitionComplete();
      },
    );

    notifyListeners();
  }

  /// Animate zoom level transition.
  void animateZoom(double from, double to) {
    if (from == to) return;

    _isTransitioning = true;
    _animatedZoom = _AnimatedValue<double>(
      from: from,
      to: to,
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedZoom = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Animate pan transition.
  void animatePan(Vector2 from, Vector2 to) {
    if (from.x == to.x && from.y == to.y) return;

    _isTransitioning = true;
    _animatedPan = _AnimatedValue<Vector2>(
      from: from.clone(),
      to: to.clone(),
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedPan = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Animate rotation transition.
  void animateRotation(Vector3 from, Vector3 to) {
    if (from.x == to.x && from.y == to.y && from.z == to.z) return;

    _isTransitioning = true;
    _animatedRotation = _AnimatedValue<Vector3>(
      from: from.clone(),
      to: to.clone(),
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedRotation = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Start a module morph transition.
  void startMorph(String fromModuleId, String toModuleId) {
    if (fromModuleId == toModuleId) return;

    _previousModuleId = fromModuleId;
    _currentModuleId = toModuleId;
    _morphProgress = 0.0;
    _isTransitioning = true;

    _morphTimer?.cancel();

    final timeline = AnimatedTimelinePlan.forDuration(morphDuration);
    if (timeline.isImmediate) {
      _finishMorphTransition();
      notifyListeners();
      return;
    }

    var step = 0;

    _morphTimer = Timer.periodic(
      timeline.frameInterval,
      (timer) {
        step++;
        _morphProgress = curve.transform(timeline.progressForFrame(step));
        notifyListeners();

        if (timeline.isCompleteFrame(step)) {
          timer.cancel();
          _finishMorphTransition();
          notifyListeners();
        }
      },
    );

    notifyListeners();
  }

  /// Get the interpolated value for a parameter.
  Object? getInterpolatedValue(String id, Object currentValue) {
    final animated = _animatedParams[id];
    if (animated == null) return null;

    if (animated is _AnimatedValue<double>) {
      return animated.currentValue;
    }
    return null;
  }

  /// Get the interpolated zoom value.
  double? get interpolatedZoom => _animatedZoom?.currentValue;

  /// Get the interpolated pan value.
  Vector2? get interpolatedPan => _animatedPan?.currentValue;

  /// Get the interpolated rotation value.
  Vector3? get interpolatedRotation => _animatedRotation?.currentValue;

  /// Record when the user finds an interesting spot.
  ///
  /// Triggers celebration effects when multiple interesting spots
  /// are found in quick succession.
  void recordInterestingSpot() {
    final now = DateTime.now();

    if (_lastInterestingSpotTime != null) {
      final elapsed = now.difference(_lastInterestingSpotTime!);
      if (elapsed.inSeconds < 30) {
        _interestingSpotCount++;

        // Trigger celebration after finding 3 interesting spots quickly
        if (_interestingSpotCount >= 3) {
          _triggerCelebration();
          _interestingSpotCount = 0;
        }
      } else {
        _interestingSpotCount = 1;
      }
    } else {
      _interestingSpotCount = 1;
    }

    _lastInterestingSpotTime = now;
    _interestingSpotController.add(null);
  }

  void _triggerCelebration() {
    _isCelebrating = true;
    notifyListeners();

    // Reset celebration after animation. Keep the timer cancellable so a
    // disposed controller cannot receive a delayed notifyListeners callback.
    _celebrationTimer?.cancel();
    _celebrationTimer = Timer(const Duration(milliseconds: 2500), () {
      _celebrationTimer = null;
      _isCelebrating = false;
      notifyListeners();
    });
  }

  /// Manually trigger a celebration effect.
  void celebrate() {
    _triggerCelebration();
  }

  void _finishMorphTransition() {
    _morphProgress = 1.0;
    _previousModuleId = null;
    _checkTransitionComplete();
  }

  void _checkTransitionComplete() {
    if (_animatedParams.isEmpty &&
        _animatedZoom == null &&
        _animatedPan == null &&
        _animatedRotation == null &&
        _morphProgress >= 1.0) {
      _isTransitioning = false;
      notifyListeners();
    }
  }

  /// Update all animations for the current frame.
  void tick() {
    var needsUpdate = false;

    for (final animated in _animatedParams.values) {
      if (animated.tick()) {
        needsUpdate = true;
      }
    }

    if (_animatedZoom?.tick() == true) needsUpdate = true;
    if (_animatedPan?.tick() == true) needsUpdate = true;
    if (_animatedRotation?.tick() == true) needsUpdate = true;

    if (needsUpdate) {
      notifyListeners();
    }
  }

  @override
  void dispose() {
    _morphTimer?.cancel();
    _celebrationTimer?.cancel();

    // Close stream controller before disposing
    if (!_interestingSpotController.isClosed) {
      _interestingSpotController.close();
    }

    super.dispose();
  }
}

/// Internal animated value helper.
class _AnimatedValue<T> {
  final T from;
  final T to;
  final Duration duration;
  final Curve curve;
  final VoidCallback? onComplete;

  final DateTime _startTime = DateTime.now();
  bool _completed = false;

  _AnimatedValue({
    required this.from,
    required this.to,
    required this.duration,
    required this.curve,
    this.onComplete,
  });

  AnimatedElapsedProgress get _elapsedProgress => AnimatedElapsedProgress(
        duration: duration,
        elapsed: DateTime.now().difference(_startTime),
      );

  double get _progress => _elapsedProgress.value;

  double get _curvedProgress => curve.transform(_progress);

  bool get isComplete => _elapsedProgress.isComplete;

  T get currentValue {
    final t = _curvedProgress;

    if (T == double) {
      return _lerpDouble(from as double, to as double, t) as T;
    } else if (T == Vector2) {
      return _lerpVector2(from as Vector2, to as Vector2, t) as T;
    } else if (T == Vector3) {
      return _lerpVector3(from as Vector3, to as Vector3, t) as T;
    }
    return to;
  }

  double _lerpDouble(double a, double b, double t) => a + (b - a) * t;

  Vector2 _lerpVector2(Vector2 a, Vector2 b, double t) {
    return Vector2(
      a.x + (b.x - a.x) * t,
      a.y + (b.y - a.y) * t,
    );
  }

  Vector3 _lerpVector3(Vector3 a, Vector3 b, double t) {
    return Vector3(
      a.x + (b.x - a.x) * t,
      a.y + (b.y - a.y) * t,
      a.z + (b.z - a.z) * t,
    );
  }

  /// Returns true if the animation is still running.
  bool tick() {
    if (_completed) return false;

    if (isComplete && !_completed) {
      _completed = true;
      onComplete?.call();
      return false;
    }

    return !_completed;
  }
}

/// Mixin to add animation capabilities to FractalController.
mixin AnimatedFractalMixin on ChangeNotifier {
  AnimatedFractalController? _animationController;

  /// The animation controller for smooth transitions.
  AnimatedFractalController get animationController {
    _animationController ??= AnimatedFractalController();
    return _animationController!;
  }

  /// Set a custom animation controller.
  set animationController(AnimatedFractalController controller) {
    _animationController = controller;
  }

  @override
  void dispose() {
    _animationController?.dispose();
    super.dispose();
  }
}

import 'dart:math';
import 'dart:ui' as ui;

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/models/fractal_palette.dart';
import 'package:flutter_fractals/core/services/palette_store.dart';

const List<FractalColorStop> _fallbackPaletteStops = [
  FractalColorStop(position: 0.0, colorArgb: 0xFF000000),
  FractalColorStop(position: 1.0, colorArgb: 0xFFFFFFFF),
];

/// Normalizes palette stops before persistence or shader texture/uniform upload.
///
/// The shader texture/uniform paths can carry at most [PaletteService.maxStops]
/// stops, but the bounded list must still span the whole gradient. When an imported
/// palette has too many stops, retain both endpoint colors and drop middle
/// candidates instead of truncating away the final 1.0 stop. A single-color
/// palette is expanded into two endpoint stops so gradient/shader consumers get
/// a replayable span instead of a one-point gradient. Non-finite stop positions
/// are dropped before sorting so malformed stops cannot become endpoint colors.
List<FractalColorStop> normalizePaletteStops(List<FractalColorStop> stops) {
  final finiteStops = _stopsWithFinitePositions(stops);
  if (finiteStops.isEmpty) return _fallbackPaletteStops;

  final sorted = [...finiteStops]
    ..sort((a, b) => a.position.compareTo(b.position));
  final clamped = sorted
      .map((stop) => stop.copyWith(
            position: _clampPaletteStopPosition(stop.position),
          ))
      .toList();

  final bounded = _capPaletteStopsPreservingEndpoint(clamped);
  final normalized = _ensurePaletteEndpointStops(bounded);

  assert(normalized.length >= 2);
  assert(normalized.length <= PaletteService.maxStops);
  assert(normalized.first.position == 0.0);
  assert(normalized.last.position == 1.0);
  return normalized;
}

List<FractalColorStop> _stopsWithFinitePositions(
  List<FractalColorStop> stops,
) {
  return stops.where((stop) => stop.position.isFinite).toList();
}

double _clampPaletteStopPosition(double position) {
  assert(position.isFinite, 'Palette stop position must be finite');
  return position.clamp(0.0, 1.0).toDouble();
}

List<FractalColorStop> _capPaletteStopsPreservingEndpoint(
  List<FractalColorStop> stops,
) {
  assert(stops.isNotEmpty);
  return stops.length > PaletteService.maxStops
      ? [
          ...stops.take(PaletteService.maxStops - 1),
          stops.last,
        ]
      : stops;
}

List<FractalColorStop> _ensurePaletteEndpointStops(
  List<FractalColorStop> stops,
) {
  assert(stops.isNotEmpty);
  if (stops.length == 1) {
    final stop = stops.single;
    return [
      stop.copyWith(position: 0.0),
      stop.copyWith(position: 1.0),
    ];
  }

  return [
    stops.first.copyWith(position: 0.0),
    ...stops.skip(1).take(stops.length - 2),
    stops.last.copyWith(position: 1.0),
  ];
}

String _uniquePaletteId(String requestedId, Set<String> reservedIds) {
  var candidate = requestedId;
  if (!reservedIds.contains(candidate)) return candidate;
  var i = 2;
  while (reservedIds.contains('$candidate-$i')) {
    i++;
  }
  return '$candidate-$i';
}

/// Manages built-in and user-created color palettes.
///
/// Palettes are persisted locally using [PaletteStore].
class PaletteService extends ChangeNotifier {
  static PaletteService? _instance;
  static PaletteService get instance {
    final v = _instance;
    if (v == null) {
      throw StateError('PaletteService not initialized');
    }
    return v;
  }

  static const int maxStops = 8;
  static const int _texWidth = 256;

  final PaletteStore _store;

  /// Cache of palette textures keyed by palette id.
  final Map<String, ui.Image> _paletteTexCache = {};

  late final List<FractalPalette> _builtIn;
  List<FractalPalette> _user = const [];

  PaletteService._(this._store) {
    _builtIn = _createBuiltIns();
  }

  static Future<PaletteService> create({PaletteStore? store}) async {
    final s = store ?? await PaletteStore.create();
    final service = PaletteService._(s);
    await service._load();
    _instance = service;
    return service;
  }

  List<FractalPalette> get builtInPalettes => List.unmodifiable(_builtIn);
  List<FractalPalette> get userPalettes => List.unmodifiable(_user);
  List<FractalPalette> get allPalettes =>
      List.unmodifiable([..._builtIn, ..._user]);

  int get builtInCount => _builtIn.length;

  FractalPalette paletteAtIndex(int index) {
    final all = allPalettes;
    if (all.isEmpty) {
      return const FractalPalette(
        id: 'fallback',
        name: 'Fallback',
        stops: _fallbackPaletteStops,
      );
    }
    if (index < 0 || index >= all.length) return all.first;
    return all[index];
  }

  bool isBuiltInIndex(int index) => index >= 0 && index < builtInCount;

  Future<void> addPalette(FractalPalette palette) async {
    await _commitUserPalettes([
      ..._user,
      _prepareNewUserPalette(palette),
    ]);
  }

  Future<void> updatePalette(FractalPalette palette) async {
    await _commitUserPalettes(
      _user
          .map((p) => p.id == palette.id
              ? palette.copyWith(
                  isBuiltIn: false,
                  stops: normalizePaletteStops(palette.stops),
                )
              : p)
          .toList(),
    );
  }

  Future<void> deletePalette(String id) async {
    await _commitUserPalettes(_user.where((p) => p.id != id).toList());
  }

  /// Imports a palette from JSON. If id is missing/duplicate, a new id is generated.
  Future<FractalPalette> importPaletteJson(String input) async {
    final palette = _prepareNewUserPalette(
      FractalPalette.fromJsonString(input),
    );
    await _commitUserPalettes([..._user, palette]);
    return palette;
  }

  String exportPaletteJson(FractalPalette palette, {bool pretty = true}) {
    return palette.copyWith(isBuiltIn: false).toJsonString(pretty: pretty);
  }

  FractalPalette createEmptyPalette({String? name}) {
    final id = _allocateUserPaletteId('');
    return FractalPalette(
      id: id,
      name: name ?? 'Custom Palette',
      stops: _fallbackPaletteStops,
      isBuiltIn: false,
    );
  }

  /// Returns a 256×1 [ui.Image] representing the palette gradient.
  ///
  /// The image is cached per palette id and reused across frames.
  /// Use with `shader.setImageSampler(0, image)` to pass palette as texture.
  ui.Image paletteTexture(FractalPalette palette) {
    final cached = _paletteTexCache[palette.id];
    if (cached != null) return cached;

    final stops = normalizePaletteStops(palette.stops);

    final rec = ui.PictureRecorder();
    final canvas = Canvas(rec, Rect.fromLTWH(0, 0, _texWidth.toDouble(), 1));
    final gradColors = stops.map((s) => Color(s.colorArgb)).toList();
    final gradStops = stops.map((s) => s.position.clamp(0.0, 1.0)).toList();
    final paint = Paint()
      ..shader = ui.Gradient.linear(
        Offset.zero,
        Offset(_texWidth.toDouble(), 0),
        gradColors,
        gradStops,
      );
    canvas.drawRect(Rect.fromLTWH(0, 0, _texWidth.toDouble(), 1), paint);
    final pic = rec.endRecording();
    final img = pic.toImageSync(_texWidth, 1);
    _paletteTexCache[palette.id] = img;
    return img;
  }

  /// Clears cached palette textures (call if palettes change).
  void invalidatePaletteTextures() {
    for (final img in _paletteTexCache.values) {
      img.dispose();
    }
    _paletteTexCache.clear();
  }

  /// Writes custom palette uniforms expected by the shaders.
  ///
  /// Layout:
  /// - [baseIndex + 0] = stopCount
  /// - then 8 vec4 stops, each: r, g, b, position
  void setCustomPaletteUniforms(
    ui.FragmentShader shader,
    int baseIndex,
    FractalPalette palette,
  ) {
    // NOTE: This API is legacy. Prefer setting palette uniforms via a
    // UniformSchema/UniformWriter to avoid hard-coded float indices.

    final stops = normalizePaletteStops(palette.stops);
    final count = stops.length.clamp(0, maxStops);
    shader.setFloat(baseIndex, count.toDouble());

    // Fill remaining with last stop to avoid NaNs in shader.
    final padded = [...stops];
    while (padded.length < maxStops) {
      padded.add(padded.last);
    }

    for (var i = 0; i < maxStops; i++) {
      final s = padded[i];
      final c = Color(s.colorArgb);
      final idx = baseIndex + 1 + i * 4;
      // Flutter 3.19 Color channels are 0-255 ints; normalize to 0.0-1.0.
      shader.setFloat(idx + 0, (c.r * 255.0).round().clamp(0, 255) / 255.0);
      shader.setFloat(idx + 1, (c.g * 255.0).round().clamp(0, 255) / 255.0);
      shader.setFloat(idx + 2, (c.b * 255.0).round().clamp(0, 255) / 255.0);
      shader.setFloat(idx + 3, s.position.clamp(0.0, 1.0));
    }
  }

  Future<void> _commitUserPalettes(List<FractalPalette> palettes) async {
    _user = palettes;
    invalidatePaletteTextures();
    await _store.savePalettes(_user);
    notifyListeners();
  }

  Future<void> _load() async {
    _user = _store
        .loadPalettes()
        .map((p) => p.copyWith(
              stops: normalizePaletteStops(p.stops),
              isBuiltIn: false,
            ))
        .toList();
    invalidatePaletteTextures();
  }

  FractalPalette _prepareNewUserPalette(FractalPalette palette) {
    return palette.copyWith(
      id: _allocateUserPaletteId(palette.id),
      isBuiltIn: false,
      stops: normalizePaletteStops(palette.stops),
    );
  }

  String _allocateUserPaletteId(String requestedId) {
    return _uniquePaletteId(
      requestedId.isEmpty ? _randomId() : requestedId,
      {..._builtIn.map((p) => p.id), ..._user.map((p) => p.id)},
    );
  }

  String _randomId() {
    final r = Random();
    final v = r.nextInt(1 << 32).toRadixString(16).padLeft(8, '0');
    return 'pal_$v';
  }

  static List<FractalPalette> _createBuiltIns() {
    return const [
      FractalPalette(
        id: 'builtin_fire',
        name: 'Fire',
        isBuiltIn: true,
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFF0D0D12),
          FractalColorStop(position: 0.35, colorArgb: 0xFF6B1D1D),
          FractalColorStop(position: 0.7, colorArgb: 0xFFF05A28),
          FractalColorStop(position: 1.0, colorArgb: 0xFFFFE066),
        ],
      ),
      FractalPalette(
        id: 'builtin_ocean',
        name: 'Ocean',
        isBuiltIn: true,
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFF06141C),
          FractalColorStop(position: 0.4, colorArgb: 0xFF0B7285),
          FractalColorStop(position: 0.8, colorArgb: 0xFF22B8CF),
          FractalColorStop(position: 1.0, colorArgb: 0xFFA5D8FF),
        ],
      ),
      FractalPalette(
        id: 'builtin_psychedelic',
        name: 'Psychedelic',
        isBuiltIn: true,
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFF3B0A45),
          FractalColorStop(position: 0.33, colorArgb: 0xFF7C3AED),
          FractalColorStop(position: 0.66, colorArgb: 0xFF06B6D4),
          FractalColorStop(position: 1.0, colorArgb: 0xFFF59E0B),
        ],
      ),
      FractalPalette(
        id: 'builtin_grayscale',
        name: 'Grayscale',
        isBuiltIn: true,
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFF000000),
          FractalColorStop(position: 1.0, colorArgb: 0xFFFFFFFF),
        ],
      ),
    ];
  }
}

